// src/components/DashboardAluno.jsx
import React, { useEffect, useState } from "react";
import axios from "axios";
import { useAuth } from "./context/AuthContext";

export default function DashboardAluno() {
  const { user } = useAuth();
  const [agendamentos, setAgendamentos] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedCard, setSelectedCard] = useState(null);

  useEffect(() => {
    axios
      .get("/api/agendamentos/meus")
      .then((res) => setAgendamentos(res.data))
      .catch((err) => console.error("Erro ao carregar agendamentos:", err))
      .finally(() => setLoading(false));
  }, []);

  // Pega hoje à meia-noite
  const hoje = new Date();
  hoje.setHours(0, 0, 0, 0);

  // Categorias
  const solicitacoes = agendamentos.filter(a => a.status === "Solicitado");
  const proximos    = agendamentos.filter(a => a.status !== "Solicitado" && a.status !== "Atendido");

  const atendidos = agendamentos.filter(a => {
    if (!a.data) return false;
    // converte "YYYY-MM-DD..." para Date
    const partes = a.data.slice(0, 10).split("-");
    const dt = new Date(partes[0], partes[1] - 1, partes[2]);
    return dt < hoje;
  });

  const firstName = (user.usuario || "").split(" ")[0];

  const cardColors = {
    solicitacoes: "bg-[#BC8C00]",
    proximos:     "bg-[#0698DC]",
    atendidos:    "bg-[#2FA74E]"
  };

  const toggleCard = (key) => {
    setSelectedCard(prev => prev === key ? null : key);
  };

  if (loading) {
    return <p className="text-center py-8">Carregando seu dashboard...</p>;
  }

  return (
    <div className="max-w-3xl mx-auto py-10 px-4">
      <h1 className="text-3xl font-bold mb-8">Olá, {firstName}!</h1>

      {/* Cards */}
      <div className="flex flex-wrap gap-4 mb-8">
        {[
          { key: "solicitacoes", label: "Minhas Solicitações", count: solicitacoes.length },
          { key: "proximos",     label: "Agendamentos Próximos", count: proximos.length },
          { key: "atendidos",    label: "Agendamentos Anteriores", count: atendidos.length },
        ].map(card => (
          <button
            key={card.key}
            onClick={() => toggleCard(card.key)}
            className={`
              min-w-[180px] flex-1 rounded-2xl px-6 py-8 text-white border-2 transition
              ${cardColors[card.key]}
              ${selectedCard === card.key
                ? "border-white bg-opacity-100"
                : "border-transparent hover:border-white hover:bg-opacity-90"
              }
            `}
          >
            <div className="font-bold text-3xl">{card.count}</div>
            <div className="mt-2">{card.label}</div>
          </button>
        ))}
      </div>

      {/* Listas expandidas */}
      {selectedCard === "solicitacoes" && (
        <div className="bg-white rounded-2xl shadow p-6 mb-6">
          <h2 className="text-lg font-bold mb-4">Últimas Solicitações</h2>
          <ul className="space-y-3">
            {solicitacoes.slice(0, 5).map(a => (
              <li
                key={a.id}
                className="flex justify-between items-center bg-gray-50 rounded-xl px-5 py-3 shadow-sm"
              >
                <span className="text-gray-800 font-medium">
                  {a.data.slice(0,10).split('-').reverse().join('/')}
                </span>
                <span className="px-4 py-1 rounded-full bg-yellow-100 text-yellow-800 font-semibold">
                  Pendente
                </span>
              </li>
            ))}
            {solicitacoes.length === 0 && (
              <li className="text-gray-500">Nenhuma solicitação pendente.</li>
            )}
          </ul>
        </div>
      )}

      {selectedCard === "proximos" && (
        <div className="bg-white rounded-2xl shadow p-6 mb-6">
          <h2 className="text-lg font-bold mb-4">Próximos Agendamentos</h2>
          <ul className="space-y-3">
            {proximos.slice(0, 5).map(a => (
              <li
                key={a.id}
                className="bg-gray-50 rounded-xl px-5 py-3 shadow-sm"
              >
                <div className="font-medium">{a.disciplinaNome || a.disciplina_id}</div>
                <div className="text-gray-600">
                  {a.data.slice(0,10).split('-').reverse().join('/')} — {a.hora}
                </div>
              </li>
            ))}
            {proximos.length === 0 && (
              <li className="text-gray-500">Nenhum agendamento próximo.</li>
            )}
          </ul>
        </div>
      )}

      {selectedCard === "atendidos" && (
        <div className="bg-white rounded-2xl shadow p-6 mb-6">
          <h2 className="text-lg font-bold mb-4">Agendamentos Anteriores</h2>
          <ul className="space-y-3">
            {atendidos.slice(0, 5).map(a => (
              <li
                key={a.id}
                className="bg-gray-50 rounded-xl px-5 py-3 shadow-sm"
              >
                <div className="font-medium">{a.disciplinaNome || a.disciplina_id}</div>
                <div className="text-gray-600">
                  {a.data.slice(0,10).split('-').reverse().join('/')} — {a.hora}
                </div>
              </li>
            ))}
            {atendidos.length === 0 && (
              <li className="text-gray-500">Nenhum agendamento anterior.</li>
            )}
          </ul>
        </div>
      )}
    </div>
  );
}
